mapper.select:
SELECT c.id, c.name, c.image_url, c.total_price, c.is_free, c.status, c.recommended, c.course_type, c.teacher, c.teacher_id, c.chapter_count, c.question_count, c.exam_count, c.video_count, c.student_count, c.view_count, c.create_time, m.name AS major_name FROM edu_course c LEFT JOIN edu_major m ON c.major_id = m.id AND m.deleted = 0 WHERE c.deleted = 0
AND c.name LIKE CONCAT('%', #{query.name}, '%')
AND c.major_id IN
#{id}
AND c.status = #{query.status}
AND c.teacher_id = #{query.teacherId}
ORDER BY c.sort ASC, c.id DESC

SELECT c.id,
       c.name,
       c.image_url,
       c.chapter_count AS total_course_time,
       IFNULL(
               ROUND(
                       (SELECT COUNT(DISTINCT sr.chapter_id)
                        FROM edu_study_record sr
                        WHERE sr.course_id = c.id
                          AND sr.student_id = #{queryParam.studentId}
                       ) / NULLIF(c.chapter_count, 0) * 100
               ), 0
       )              AS learn_progress,
       (SELECT MAX(sr.update_time)
        FROM edu_study_record sr
        WHERE sr.course_id = c.id
          AND sr.student_id = #{queryParam.studentId}
       )              AS recent_learn_time
FROM edu_course c
WHERE c.deleted = 0
  AND c.id IN (
    SELECT DISTINCT sr.course_id
    FROM edu_study_record sr
    WHERE sr.student_id = #{queryParam.studentId}
)
ORDER BY recent_learn_time DESC
